svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = ctx.$$("#data-layer");
    var legendRoot = ctx.$$("#legend-root");
    var tiles = ctx.$$all(".tile-node");
    var tip;
    if (!dataLayerEl || !tiles.length) return;

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      x: 864,
      y: 88,
      width: 208,
      height: 455,
      titleX: 884,
      titleY: 118,
      rowX: 884,
      rowStartY: 146,
      rowGap: 42,
      valueX: 168,
      items: [
        { cls: 'series-5', label: 'Violet', value: '$320M' },
        { cls: 'series-1', label: 'Cyan', value: '$210M' },
        { cls: 'series-2', label: 'Emerald', value: '$150M' },
        { cls: 'series-3', label: 'Amber', value: '$120M' },
        { cls: 'series-6', label: 'Blue', value: '$85M' },
        { cls: 'series-7', label: 'Teal', value: '$65M' },
        { cls: 'series-4', label: 'Rose', value: '$45M' },
        { cls: 'series-8', label: 'Other', value: '$30M' }
      ]
    });

    ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      outerLeft: 24,
      legendGap: 32
    });

    var tileTiming = ctx.getStaggerTiming(tiles.length, null, svgEl);
    var tileDelays = tiles.map(function (_, index) {
      return ctx.getStaggerDelay(index, tiles.length, null, svgEl);
    });
    ctx.initRevealSequence(tiles, {
      animationName: 'tileFade',
      duration: tileTiming.duration,
      easing: 'ease-out',
      delays: tileDelays
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: tileDelays,
      duration: tileTiming.duration,
      buffer: tileTiming.buffer
    });

    tip = ctx.el('g', { 'class': 'tip', id: 'tip', style: 'opacity:0;pointer-events:none;' });
    tip.appendChild(ctx.el('rect', { id: 'tip-bg', 'class': 'tip-bg', rx: '9' }));
    tip.appendChild(ctx.el('path', { id: 'tip-bdr', 'class': 'tip-border' }));
    tip.appendChild(ctx.el('path', { id: 'tip-tail', 'class': 'tip-tail' }));
    tip.appendChild(ctx.el('text', { id: 'tip-val', 'class': 'tip-value', 'text-anchor': 'middle', 'dominant-baseline': 'central' }));
    tip.appendChild(ctx.el('text', { id: 'tip-lbl', 'class': 'tip-label', 'text-anchor': 'middle', 'dominant-baseline': 'central' }));
    tip.appendChild(ctx.el('text', { id: 'tip-meta', 'class': 'tip-pct', 'text-anchor': 'middle', 'dominant-baseline': 'central' }));
    svgEl.appendChild(tip);

    ctx.initStandardTooltip(dataLayerEl, tiles, {
      tip: tip,
      plotL: 24,
      plotR: 850,
      plotT: 100,
      plotB: 500,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getContent: function (tile) {
        var lines = Array.prototype.slice.call(tile.querySelectorAll('text'));
        var title = lines[0] ? lines[0].textContent : '';
        var sub = lines[1] ? lines[1].textContent : '';
        var parts = sub.split(/\s*[ - ]\s*/);
        return {
          primary: parts[0] ? parts[0].trim() : '',
          label: title,
          meta: parts[1] ? parts[1].trim() : ''
        };
      },
      leaveTarget: dataLayerEl
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
